# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews. Prevent XSS (Cross-Site Scripting) attacks.
# Category: xss

using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Security.Cryptography;
using System.Text.RegularExpressions;

namespace MyMvcApp.Controllers
{
    public class ProductController : Controller
    {
        private readonly MyDbContext _context;

        public ProductController(MyDbContext context)
        {
            _context = context;
        }

        [HttpGet]
        public ActionResult Reviews(int productId)
        {
            var reviews = _context.Reviews
                .Where(r => r.ProductId == productId)
                .OrderByDescending(r => r.CreatedAt)
                .ToList();

            return View(reviews);
        }

        [HttpPost]
        public ActionResult SubmitReview(Review review)
        {
            if (ModelState.IsValid)
            {
                var sanitizedText = Sanitize(review.Text);

                _context.Reviews.Add(new Review
                {
                    ProductId = review.ProductId,
                    Text = sanitizedText,
                    CreatedAt = DateTime.Now
                });

                _context.SaveChanges();

                return RedirectToAction("Reviews", new { productId = review.ProductId });
            }

            return View("SubmitReview");
        }

        private string Sanitize(string text)
        {
            var allowedTags = new[] { "b", "i" };
            var pattern = new Regex("<(/?)(" + string.Join("|", allowedTags) + ")[^>]*>");
            return pattern.Replace(text, match => match.Groups[1].Value == "/" ? "</" + match.Groups[2].Value + ">" : "<" + match.Groups[2].Value + ">");
        }
    }

    public class Review
    {
        public int ProductId { get; set; }
        public string Text { get; set; }
        public DateTime CreatedAt { get; set; }
    }
}